Use `Union` or the `|` operator (Python 3.10+) for multiple return types:

```python
from typing import Union

# Python 3.10+ syntax (preferred)
def parse_value(value: str) -> int | float | None:
    """Parse a string value to int, float, or None."""
    if not value.strip():
        return None
    try:
        return int(value)
    except ValueError:
        try:
            return float(value)
        except ValueError:
            return None

# Older Python syntax
def parse_value_legacy(value: str) -> Union[int, float, None]:
    try:
        return int(value)
    except ValueError:
        try:
            return float(value)
        except ValueError:
            return None
```

