```python
import json
from typing import Any

def parse_llm_json(text: str) -> dict[str, Any]:
    """Parse JSON from LLM output, handling common formatting issues.

    LLMs often wrap JSON in markdown code blocks or add
    extra text before/after the JSON.
    """
    # Try direct parse first
    try:
        return json.loads(text)
    except json.JSONDecodeError:
        pass

    # Try extracting from markdown code block
    if '```json' in text:
        start = text.index('```json') + 7
        end = text.index('```', start)
        json_str = text[start:end].strip()
        return json.loads(json_str)
    elif '```' in text:
        start = text.index('```') + 3
        end = text.index('```', start)
        json_str = text[start:end].strip()
        return json.loads(json_str)

    # Try finding first { to last }
    first_brace = text.find('{')
    last_brace = text.rfind('}')
    if first_brace != -1 and last_brace != -1:
        json_str = text[first_brace:last_brace + 1]
        return json.loads(json_str)

    raise ValueError(f"Could not extract valid JSON from LLM output")


# Usage with validation schema
def validate_llm_output(text: str, required_keys: list[str]) -> dict[str, Any]:
    """Parse and validate LLM JSON output."""
    data = parse_llm_json(text)

    missing = [k for k in required_keys if k not in data]
    if missing:
        raise ValueError(f"Missing required keys: {missing}")

    return data
```

Here's how to create a basic tool-using agent with OpenClaw:

```python
import json
import subprocess

# Agent configuration
config = {
    "model_provider": "openai",
    "api_base": "http://127.0.0.1:11435/v1",
    "model": "local-model",
    "tools": [
        {
            "name": "run_command",
            "description": "Run a shell command and return output",
            "parameters": {
                "type": "object",
                "properties": {
                    "command": {"type": "string"}
                },
                "required": ["command"]
            }
        },
        {
            "name": "read_file",
            "description": "Read a file's contents",
            "parameters": {
                "type": "object",
                "properties": {
                    "path": {"type": "string"}
                },
                "required": ["path"]
            }
        }
    ]
}

# Tool implementations
def run_command(command: str) -> str:
    """Execute a command safely."""
    # Safety: block dangerous commands
    blocked = ['rm -rf /', 'format', 'del /s', 'mkfs']
    if any(b in command for b in blocked):
        return f"Blocked: command contains dangerous pattern"
    try:
        result = subprocess.run(
            command, shell=True, capture_output=True, text=True, timeout=30
        )
        return result.stdout[:2000] or result.stderr[:2000]
    except subprocess.TimeoutExpired:
        return "Error: Command timed out"

def read_file(path: str) -> str:
    """Read file contents safely."""
    try:
        with open(path, encoding='utf-8') as f:
            return f.read()[:5000]
    except FileNotFoundError:
        return f"Error: File not found: {path}"
    except PermissionError:
        return f"Error: Permission denied: {path}"
```

Always implement safety checks in tool handlers. Never allow arbitrary command execution without validation.

```python
from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import Optional

app = FastAPI(title="My API", version="1.0.0")

# Data model
class Item(BaseModel):
    name: str
    description: Optional[str] = None
    price: float

# In-memory storage (replace with database)
items: dict[int, Item] = {}

@app.get("/items/{item_id}")
def get_item(item_id: int) -> Item:
    if item_id not in items:
        raise HTTPException(status_code=404, detail="Item not found")
    return items[item_id]

@app.post("/items", status_code=201)
def create_item(item: Item) -> dict:
    item_id = len(items) + 1
    items[item_id] = item
    return {"id": item_id, **item.model_dump()}

@app.get("/health")
def health() -> dict:
    return {"status": "ok"}

# Run with: uvicorn main:app --host 127.0.0.1 --port 8000
```

Key practices:
- Bind to `127.0.0.1` for local-only access
- Use Pydantic models for request/response validation
- Use proper HTTP status codes
- Add error handling with HTTPException
- Use type hints throughout
